const workflowResponse = $('Fetch Workflow Inventory').first().json || {};
const executionResponse = $('Fetch Recent Executions').first().json || {};
const workflows = Array.isArray(workflowResponse.data) ? workflowResponse.data : [];
const executions = Array.isArray(executionResponse.data) ? executionResponse.data : [];
const now = new Date().toISOString();
const executionRows = executions.map(e => {
  const started = Date.parse(e.startedAt || '');
  const stopped = Date.parse(e.stoppedAt || '');
  const duration = Number.isFinite(started) && Number.isFinite(stopped) ? Math.max(0, stopped - started) : null;
  return {
    execution_id: String(e.id),
    workflow_id: String(e.workflowId),
    status: e.status || 'unknown',
    mode: e.mode || '',
    finished: Boolean(e.finished),
    started_at: e.startedAt,
    stopped_at: e.stoppedAt || null,
    duration_ms: duration,
    wait_till: e.waitTill || null,
    retry_of: e.retryOf || null,
    retry_success_id: e.retrySuccessId || null,
    execution_url: `PLACEHOLDER_N8N_EDITOR_BASE_URL/workflow/${e.workflowId}/executions/${e.id}`,
    collected_at: now,
    raw_summary: { finished: e.finished, status: e.status, mode: e.mode }
  };
});
const byWorkflow = new Map();
for (const e of executionRows) {
  const current = byWorkflow.get(e.workflow_id) || {};
  if (!current.last_execution_at || e.started_at > current.last_execution_at) current.last_execution_at = e.started_at;
  if (e.status === 'success' && (!current.last_success_at || e.started_at > current.last_success_at)) current.last_success_at = e.started_at;
  if (e.status === 'error' && (!current.last_error_at || e.started_at > current.last_error_at)) current.last_error_at = e.started_at;
  byWorkflow.set(e.workflow_id, current);
}
const workflowRows = workflows.map(w => {
  const recent = byWorkflow.get(String(w.id)) || {};
  return {
    workflow_id: String(w.id),
    name: w.name || `Workflow ${w.id}`,
    active: Boolean(w.active),
    error_workflow_id: w.settings?.errorWorkflow || null,
    tags: w.tags || [],
    last_execution_at: recent.last_execution_at || null,
    last_success_at: recent.last_success_at || null,
    last_error_at: recent.last_error_at || null,
    current_health: !w.active ? 'inactive' : recent.last_error_at && (!recent.last_success_at || recent.last_error_at > recent.last_success_at) ? 'warning' : recent.last_success_at ? 'healthy' : 'unknown',
    updated_at: now
  };
});
return [{json:{workflow_rows:workflowRows,execution_rows:executionRows,next_cursor:executionResponse.nextCursor || null,collected_at:now,workflow_count:workflowRows.length,execution_count:executionRows.length}}];
